package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class GsonBuilderSerializeNullsTest {

  @Test
  void serializeNulls_shouldSetSerializeNullsTrueAndReturnThis() throws Exception {
    GsonBuilder gsonBuilder = new GsonBuilder();

    // Before calling serializeNulls(), serializeNulls field should be false (default)
    boolean beforeValue = (boolean) getPrivateField(gsonBuilder, "serializeNulls");
    assertFalse(beforeValue);

    // Call focal method
    GsonBuilder returned = gsonBuilder.serializeNulls();

    // After calling serializeNulls(), serializeNulls field should be true
    boolean afterValue = (boolean) getPrivateField(gsonBuilder, "serializeNulls");
    assertTrue(afterValue);

    // Method should return the same instance (this)
    assertSame(gsonBuilder, returned);
  }

  private Object getPrivateField(Object instance, String fieldName) throws Exception {
    Class<?> clazz = instance.getClass();
    Field field = null;
    while (clazz != null) {
      try {
        field = clazz.getDeclaredField(fieldName);
        break;
      } catch (NoSuchFieldException e) {
        clazz = clazz.getSuperclass();
      }
    }
    if (field == null) {
      throw new NoSuchFieldException(fieldName);
    }
    field.setAccessible(true);
    return field.get(instance);
  }
}
